pub fn push_first_header_key(headers: &mut Vec<String>) {
    let first = headers.first().unwrap_or(&String::from("x-default"));
    headers.push(first.to_ascii_lowercase());
}

pub fn push_first_header_key(headers: &mut Vec<String>) {
    let first = headers
        .first()
        .cloned()
        .unwrap_or_else(|| "x-default".to_string());
    headers.push(first.to_ascii_lowercase());
}
